export type GameIconName = keyof typeof PATHS;

/** Badge icon IDs stored in the DB seed (seed-badges.ts) → gold icons. */
export const BADGE_ICONS: Record<string, GameIconName> = {
  "flame": "fire",
  "bee": "bee",
  "medal": "medal",
  "star": "star",
  "trophy": "trophy",
  "crown": "crown",
  "fire-ring": "fireRing",
  "fire-crown": "fireCrown",
  "diamond": "diamond",
  "gem": "gem",
  "scroll": "scroll",
  "book": "book",
  "shield": "shield",
  "sword": "broadsword",
  "compass": "compass",
  "map": "map",
  "lightning": "lightning",
  "sunrise": "sunrise",
  "moon": "moon",
  "hourglass": "hourglass",
  "clock": "clock",
  "infinity": "infinity",
  "brain": "brain",
  "telescope": "telescope",
  "timer": "timer",
  "calendar": "calendar",
  "scales": "scales",
  "sun": "sun",
};

/** Castle upgrade types → gold icons, ascending tier order. */
export const CASTLE_ICONS: Record<string, GameIconName> = {
  campsite: "tent",
  cottage: "house",
  watchtower: "watchtower",
  keep: "stoneTower",
  manor: "capitol",
  castle: "castle",
  fortress: "castle",
  citadel: "castle",
};

export function GameIcon({
  name,
  className,
}: {
  name: GameIconName;
  className?: string;
}) {
  return (
    <svg
      viewBox="0 0 512 512"
      role="img"
      aria-hidden="true"
      className={className}
      dangerouslySetInnerHTML={{ __html: PATHS[name] }}
    />
  );
}
